// src/lib/datetime.test.ts
import { describe, it, expect } from 'vitest';
import { formatDate, formatTime, formatDateTime } from './datetime';

const D = new Date('2026-05-07T00:04:09'); // midnight, single-digit month/day/min/sec

describe('formatDate', () => {
  it('formats MDY for mdy12 and mdy24', () => {
    expect(formatDate(D, 'mdy12')).toBe('5/7/2026');
    expect(formatDate(D, 'mdy24')).toBe('5/7/2026');
  });

  it('formats DMY for dmy12 and dmy24', () => {
    expect(formatDate(D, 'dmy12')).toBe('7/5/2026');
  });

  it('formats ISO for ymd24', () => {
    expect(formatDate(D, 'ymd24')).toBe('2026-05-07');
  });
});

describe('formatTime', () => {
  it('midnight renders as 12:04:09 AM in 12h', () => {
    expect(formatTime(D, 'mdy12', true)).toBe('12:04:09 AM');
  });

  it('noon renders as 12:xx PM in 12h', () => {
    const noon = new Date('2026-05-07T12:00:00');
    expect(formatTime(noon, 'mdy12', true)).toBe('12:00:00 PM');
  });

  it('uses 24h format for mdy24', () => {
    expect(formatTime(D, 'mdy24', true)).toBe('00:04:09');
  });

  it('omits seconds when showSeconds=false', () => {
    expect(formatTime(D, 'mdy12', false)).toBe('12:04 AM');
    expect(formatTime(D, 'ymd24', false)).toBe('00:04');
  });
});

describe('formatDateTime', () => {
  it('combines date and time with separator', () => {
    expect(formatDateTime(D, 'mdy12')).toBe('5/7/2026 · 12:04:09 AM');
  });

  it('returns only time when showDate=false', () => {
    expect(formatDateTime(D, 'mdy24', { showDate: false })).toBe('00:04:09');
  });

  it('omits seconds when showSeconds=false', () => {
    expect(formatDateTime(D, 'mdy12', { showSeconds: false })).toBe('5/7/2026 · 12:04 AM');
  });
});
