// src/lib/stock.test.ts
import { describe, it, expect } from 'vitest';
import { detectStockTerm } from './stock';

describe('detectStockTerm', () => {
  it('returns null for empty query', () => {
    expect(detectStockTerm('')).toBeNull();
    expect(detectStockTerm('   ')).toBeNull();
  });

  // $TICKER form
  it('detects explicit $TICKER and marks exact=true', () => {
    expect(detectStockTerm('$AAPL')).toEqual({ term: 'AAPL', exact: true });
    expect(detectStockTerm('price of $tsla today')).toEqual({ term: 'TSLA', exact: true });
  });

  // keyword form
  it('detects "stock" keyword and strips noise words', () => {
    const result = detectStockTerm('tesla stock price');
    expect(result?.exact).toBe(false);
    expect(result?.term).toBe('tesla');
  });

  it('detects share price keyword', () => {
    expect(detectStockTerm('share price of apple')).toMatchObject({ exact: false });
  });

  // bare token form
  it('detects a bare short uppercase-eligible token as exact', () => {
    expect(detectStockTerm('tsla')).toEqual({ term: 'TSLA', exact: true });
    expect(detectStockTerm('AAPL')).toEqual({ term: 'AAPL', exact: true });
  });

  it('does not match stopwords as tickers', () => {
    expect(detectStockTerm('the')).toBeNull();
    expect(detectStockTerm('jobs')).toBeNull();
    expect(detectStockTerm('news')).toBeNull();
  });

  it('does not match bare tokens longer than 5 chars', () => {
    expect(detectStockTerm('google')).toBeNull();
  });

  it('returns null for plain multi-word queries', () => {
    expect(detectStockTerm('how to bake bread')).toBeNull();
  });
});
