```ts
// src/lib/server/altcha.test.ts
import { describe, it, expect, vi } from 'vitest';
import { createChallenge, verifySolution } from './altcha';

function solveChallenge(challenge: ReturnType<typeof createChallenge>): string {
  for (let n = 0; n <= challenge.maxnumber; n++) {
    const hash = require('node:crypto')
      .createHash('sha256')
      .update(challenge.salt + n)
      .digest('hex');
    if (hash === challenge.challenge) {
      return Buffer.from(JSON.stringify({
        algorithm: challenge.algorithm,
        challenge: challenge.challenge,
        number: n,
        salt: challenge.salt,
        signature: challenge.signature,
      })).toString('base64');
    }
  }
  throw new Error('Could not solve challenge');
}

describe('createChallenge', () => {
  it('returns required fields with correct algorithm', () => {
    const c = createChallenge();
    expect(c.algorithm).toBe('SHA-256');
    expect(c.challenge).toMatch(/^[0-9a-f]{64}$/);
    expect(c.signature).toMatch(/^[0-9a-f]{64}$/);
    expect(c.salt).toContain('.');
  });

  it('encodes a future expiry in the salt', () => {
    const before = Date.now();
    const c = createChallenge();
    const expiry = Number(c.salt.split('.')[1]);
    expect(expiry).toBeGreaterThan(before);
  });
});

describe('verifySolution', () => {
  it('accepts a correctly solved challenge', () => {
    const c = createChallenge(100);
    const payload = solveChallenge(c);
    expect(verifySolution(payload)).toBe(true);
  });

  it('rejects a replayed solution', () => {
    const c = createChallenge(100);
    const payload = solveChallenge(c);
    expect(verifySolution(payload)).toBe(true);
    expect(verifySolution(payload)).toBe(false); // replay
  });

  it('rejects an expired challenge', () => {
    const c = createChallenge(100);
    // Forge an expired salt by replacing the expiry with a past timestamp
    const [randPart] = c.salt.split('.');
    const expiredSalt = `${randPart}.${Date.now() - 1}`;
    const payload = Buffer.from(JSON.stringify({
      algorithm: c.algorithm,
      challenge: c.challenge,
      number: 0,
      salt: expiredSalt,
      signature: c.signature,
    })).toString('base64');
    expect(verifySolution(payload)).toBe(false);
  });

  it('rejects a tampered challenge hash', () => {
    const c = createChallenge(100);
    const payload = Buffer.from(JSON.stringify({
      ...c,
      number: 0,
      challenge: 'a'.repeat(64), // wrong hash
    })).toString('base64');
    expect(verifySolution(payload)).toBe(false);
  });

  it('rejects missing required fields', () => {
    const payload = Buffer.from(JSON.stringify({ algorithm: 'SHA-256' })).toString('base64');
    expect(verifySolution(payload)).toBe(false);
  });

  it('rejects malformed base64', () => {
    expect(verifySolution('!!!not-base64!!!')).toBe(false);
  });

  it('rejects wrong algorithm', () => {
    const c = createChallenge(100);
    const payload = Buffer.from(JSON.stringify({
      ...c, number: 0, algorithm: 'MD5',
    })).toString('base64');
    expect(verifySolution(payload)).toBe(false);
  });

  it('rejects non-finite number field', () => {
    const c = createChallenge(100);
    const payload = Buffer.from(JSON.stringify({
      ...c, number: NaN,
    })).toString('base64');
    expect(verifySolution(payload)).toBe(false);
  });
});
