// src/lib/server/security.test.ts
import { describe, it, expect, vi, beforeEach } from 'vitest';
import {
  flagSuspicious, markVerified, isVerified, challengeRequired, getClientKey
} from './security';

// security.ts uses module-level Maps — reset between tests by re-importing
// or by controlling time. Use vi.setSystemTime.

beforeEach(() => {
  vi.useFakeTimers();
  vi.setSystemTime(0);
});

afterEach(() => vi.useRealTimers());

describe('flagSuspicious / challengeRequired', () => {
  it('unflagged client does not require challenge', () => {
    expect(challengeRequired('1.2.3.4')).toBe(false);
  });

  it('flagged client requires challenge', () => {
    flagSuspicious('1.2.3.4');
    expect(challengeRequired('1.2.3.4')).toBe(true);
  });

  it('challenge no longer required after flag window expires', () => {
    flagSuspicious('1.2.3.4');
    vi.advanceTimersByTime(5 * 60_000 + 1);
    expect(challengeRequired('1.2.3.4')).toBe(false);
  });
});

describe('markVerified / isVerified', () => {
  it('not verified before markVerified', () => {
    expect(isVerified('5.6.7.8')).toBe(false);
  });

  it('verified after markVerified', () => {
    markVerified('5.6.7.8');
    expect(isVerified('5.6.7.8')).toBe(true);
  });

  it('verification expires after window', () => {
    markVerified('5.6.7.8');
    vi.advanceTimersByTime(15 * 60_000 + 1);
    expect(isVerified('5.6.7.8')).toBe(false);
  });

  it('verified client does not require challenge even while flagged', () => {
    flagSuspicious('1.2.3.4');
    markVerified('1.2.3.4');
    expect(challengeRequired('1.2.3.4')).toBe(false);
  });
});

describe('getClientKey', () => {
  const makeEvent = (forwarded?: string, addr = '') => ({
    request: { headers: { get: (h: string) => h === 'x-forwarded-for' ? forwarded ?? null : null } },
    getClientAddress: () => addr,
  });

  it('returns first IP from X-Forwarded-For', () => {
    expect(getClientKey(makeEvent('10.0.0.1, 10.0.0.2') as any)).toBe('10.0.0.1');
  });

  it('falls back to getClientAddress', () => {
    expect(getClientKey(makeEvent(undefined, '9.9.9.9') as any)).toBe('9.9.9.9');
  });

  it('falls back to "unknown" when nothing is available', () => {
    expect(getClientKey(makeEvent(undefined, '') as any)).toBe('unknown');
  });
});
