// src/lib/server/ai.test.ts
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { summarizeResults, getCachedAnswer, setCachedAnswer } from './ai';

// Stub env so GROQ_API_KEY can be toggled per-test
vi.mock('$env/dynamic/private', () => ({ env: { GROQ_API_KEY: 'test-key' } }));
vi.mock('./kv', () => ({ getRedis: () => null }));

beforeEach(() => vi.useFakeTimers());
afterEach(() => vi.useRealTimers());

const SOURCES = [
  { title: 'Result 1', snippet: 'Svelte is a compiler.', url: 'https://svelte.dev' },
];

describe('summarizeResults', () => {
  it('returns null when sources array is empty', async () => {
    const result = await summarizeResults('svelte', [], fetch);
    expect(result).toBeNull();
  });

  it('returns answer text on successful API response', async () => {
    const mockFetch = vi.fn().mockResolvedValue({
      ok: true,
      json: async () => ({
        choices: [{ message: { content: 'Svelte is a compiler.' } }],
      }),
    });
    const result = await summarizeResults('svelte', SOURCES, mockFetch as any);
    expect(result).toBe('Svelte is a compiler.');
  });

  it('returns null on non-ok HTTP response', async () => {
    const mockFetch = vi.fn().mockResolvedValue({ ok: false });
    expect(await summarizeResults('svelte', SOURCES, mockFetch as any)).toBeNull();
  });

  it('returns null when fetch times out (AbortError)', async () => {
    const mockFetch = vi.fn().mockRejectedValue(new DOMException('Aborted', 'AbortError'));
    expect(await summarizeResults('svelte', SOURCES, mockFetch as any)).toBeNull();
  });

  it('returns null when choices array is missing', async () => {
    const mockFetch = vi.fn().mockResolvedValue({
      ok: true, json: async () => ({}),
    });
    expect(await summarizeResults('svelte', SOURCES, mockFetch as any)).toBeNull();
  });
});

describe('getCachedAnswer / setCachedAnswer (local cache)', () => {
  it('returns null on a cold cache', async () => {
    expect(await getCachedAnswer('no-such-query')).toBeNull();
  });

  it('returns a stored answer', async () => {
    const answer = { answer: 'hello', sources: [] };
    await setCachedAnswer('my-query', answer);
    expect(await getCachedAnswer('my-query')).toEqual(answer);
  });

  it('returns null after TTL expires', async () => {
    await setCachedAnswer('expiring-query', { answer: 'hi', sources: [] });
    vi.advanceTimersByTime(60 * 60_000 + 1);
    expect(await getCachedAnswer('expiring-query')).toBeNull();
  });
});
