it('retryAfterSeconds is at least 1 when bucket is empty', () => {
  const drained: TokenBucketState = { tokens: 0, lastRefillAt: 0, updatedAt: 0 };
  const decision = consumeTokenBucket(drained, OPTIONS, 0);
  expect(decision.retryAfterSeconds).toBeGreaterThanOrEqual(1);
});

it('partial refill interval does not add a token', () => {
  const drained: TokenBucketState = { tokens: 0, lastRefillAt: 0, updatedAt: 0 };
  // Half an interval passes — no token yet
  const decision = consumeTokenBucket(drained, OPTIONS, Math.floor(OPTIONS.refillIntervalMs / 2));
  expect(decision.allowed).toBe(false);
});

it('caps refill at capacity regardless of elapsed time', () => {
  const drained: TokenBucketState = { tokens: 0, lastRefillAt: 0, updatedAt: 0 };
  const decision = consumeTokenBucket(drained, OPTIONS, OPTIONS.refillIntervalMs * 1000);
  expect(decision.state.tokens).toBeLessThanOrEqual(OPTIONS.capacity - 1);
});
